functions.FunctionCallAnalyzer.analyze_project:
def analyze_project(self) -> Dict:
        """分析整个项目的函数调用关系。

        Returns:
            包含函数定义和调用关系的字典
        """
        # 遍历所有Python文件
        for root, dirs, files in os.walk(self.root_dir):
            # 跳过缓存目录
            dirs[:] = [d for d in dirs if not d.startswith('__pycache__')]

            for file in files:
                if file.endswith('.py'):
                    file_path = os.path.join(root, file)
                    self._analyze_file(file_path)

        return {
            'functions': dict(self.function_definitions),
            'calls': {k: list(v) for k, v in self.function_calls.items()},
            'callers': {k: list(v) for k, v in self.callers.items()}
        }

functions.FunctionCallAnalyzer._analyze_file:
def _analyze_file(self, file_path: str):
        """分析单个Python文件。

        Args:
            file_path: 文件路径
        """
        try:
            with open(file_path, 'r', encoding='utf-8') as f:
                content = f.read()

            tree = ast.parse(content)
            analyzer = FunctionVisitor(file_path, self.root_dir)
            analyzer.visit(tree)

            # 合并结果
            for func_name, calls in analyzer.function_calls.items():
                self.function_calls[func_name].update(calls)
                for called in calls:
                    self.callers[called].add(func_name)

            for func_name, definition in analyzer.function_definitions.items():
                self.function_definitions[func_name] = definition

        except Exception as e:
            print(f"Error analyzing {file_path}: {e}")

functions.FunctionCallAnalyzer.dfs:
def dfs(current_func: str, path: List[str], depth: int):
            if depth >= max_depth or current_func in visited:
                if path:
                    chains.append(path.copy())
                return

            visited.add(current_func)
            path.append(current_func)

            for called_func in self.function_calls.get(current_func, set()):
                dfs(called_func, path, depth + 1)

            path.pop()
            visited.remove(current_func)

functions.FunctionVisitor.visit_AsyncFunctionDef:
def visit_AsyncFunctionDef(self, node: ast.AsyncFunctionDef):
        """访问异步函数定义."""
        self.visit_FunctionDef(node)

functions.FunctionVisitor.visit_Call:
def visit_Call(self, node: ast.Call):
        """访问函数调用."""
        if self.current_function:
            # 提取被调用的函数名
            called_func = self._extract_function_name(node.func)
            if called_func:
                self.function_calls[self.current_function].add(called_func)

        self.generic_visit(node)

functions.FunctionVisitor._extract_function_name:
def _extract_function_name(self, node: ast.AST) -> Optional[str]:
        """从AST节点提取函数名."""
        if isinstance(node, ast.Name):
            return node.id
        elif isinstance(node, ast.Attribute):
            # 处理方法调用如 obj.method()
            value_name = self._extract_function_name(node.value)
            if value_name:
                return f"{value_name}.{node.attr}"
            else:
                return node.attr
        elif isinstance(node, ast.Call):
            # 嵌套调用
            return self._extract_function_name(node.func)
        return None

functions.FunctionQuery._find_analysis_file:
def _find_analysis_file(self) -> str:
        """自动查找函数分析文件."""
        # 先检查当前目录
        if os.path.exists("function_analysis.json"):
            return "function_analysis.json"

        # 检查tlexe_build目录
        if os.path.exists("tlexe_build/function_analysis.json"):
            return "tlexe_build/function_analysis.json"

        # 递归查找
        for root, dirs, files in os.walk("."):
            # 跳过缓存目录
            dirs[:] = [d for d in dirs if not d.startswith('__pycache__')]

            if "function_analysis.json" in files:
                return os.path.join(root, "function_analysis.json")

        # 如果找不到，返回默认路径
        return "function_analysis.json"

functions.FunctionQuery._load_analysis:
def _load_analysis(self, file_path: str) -> Dict:
        """加载函数分析结果."""
        try:
            with open(file_path, 'r', encoding='utf-8') as f:
                return json.load(f)
        except FileNotFoundError:
            print(f"Warning: Analysis file {file_path} not found. Returning empty data.")
            return {'functions': {}, 'calls': {}, 'callers': {}}
        except json.JSONDecodeError as e:
            print(f"Error: Failed to parse {file_path}: {e}")
            return {'functions': {}, 'calls': {}, 'callers': {}}

