            'passed': ('✓ 通过', '#00aa00'),
            'failed': ('✗ 失败', '#ff4444'),
            'error': ('✗ 错误', '#ff0000'),
        }

        status_text, color = status_map.get(result['status'], ('未知', '#888888'))
        item.setText(1, status_text)
        item.setForeground(1, QColor(color))

