def unsubscribe_all(self, signal: Signal):
        """取消指定信号的所有订阅。

        断开所有连接到指定信号的回调函数。

        Args:
            signal: 要取消订阅的信号
        """
        signal_name = signal.signal
        if signal_name in self._subscribers:
            for callback in self._subscribers[signal_name]:
