functions.ImageCarouselModel.next_image:
def next_image(self):
        """切换到下一张图片。"""
        if not self._images:
            return
        if self._loop:
            self.current_index = (self._current_index + 1) % len(self._images)
        else:
            if self._current_index < len(self._images) - 1:
                self.current_index = self._current_index + 1

functions.ImageCarouselModel.prev_image:
def prev_image(self):
        """切换到上一张图片。"""
        if not self._images:
            return
        if self._loop:
            self.current_index = (self._current_index - 1) % len(self._images)
        else:
            if self._current_index > 0:
                self.current_index = self._current_index - 1

functions.ImageCarouselModel.random_image:
def random_image(self):
        """随机切换到一张图片。"""
        import random
        if len(self._images) > 1:
            new_index = random.randint(0, len(self._images) - 1)
            self.current_index = new_index

