        """安全关闭窗口，防止内存泄漏。"""
        try:
            window.disconnect()
        except:
            pass

        if self._linkage_manager:
            try:
                self._linkage_manager.clear_linkages()
            except Exception as e:
                debug_log('general', f"清理联动连接失败: {e}", force=True)

        window.setAttribute(Qt.WA_DeleteOnClose, True)
        window.close()
        window.deleteLater()

        self._windows.pop(window_id, None)

