functions.IconTestWindow._setup_ui:
def _setup_ui(self):
        """初始化UI。"""
        central_widget = QWidget()
        self.setCentralWidget(central_widget)

        layout = QVBoxLayout(central_widget)
        layout.setContentsMargins(20, 20, 20, 20)
        layout.setSpacing(20)

        title = QLabel("黑白UI图标展示")
        title.setStyleSheet("""
            QLabel {
                font-size: 18px;
                font-weight: bold;
                color: #333;
                padding: 10px;
            }
        """)
        title.setAlignment(Qt.AlignmentFlag.AlignCenter)
        layout.addWidget(title)

        grid_layout = QGridLayout()
        grid_layout.setSpacing(15)

        icons = IconManager.get_available_icons()
        icons.sort()

        row = 0
        col = 0
        max_cols = 4

        for icon_name in icons:
            icon_widget = self._create_icon_widget(icon_name)
            grid_layout.addWidget(icon_widget, row, col)

            col += 1
            if col >= max_cols:
                col = 0
                row += 1

        layout.addLayout(grid_layout)
        layout.addStretch()

        info_label = QLabel(
            "提示：这些图标已替换组件面板中的文本图标\n"
            "图标格式：SVG矢量图标（可缩放，黑白风格）"
        )
        info_label.setStyleSheet("""
            QLabel {
                font-size: 12px;
                color: #666;
                padding: 10px;
                background-color: #f5f5f5;
                border-radius: 5px;
            }
        """)
        info_label.setAlignment(Qt.AlignmentFlag.AlignCenter)
        layout.addWidget(info_label)

