functions.run_test:
def run_test(test_name: str, result: TestResult):
    """装饰器：运行单个测试。"""
    def decorator(func):
        try:
            func()
            result.add_pass(test_name)
        except Exception as e:
            error_msg = f"{type(e).__name__}: {str(e)}"
            result.add_fail(test_name, error_msg)
        return func
