def _create_image(model) -> QWidget:
        """创建图片控件。"""
        from PySide6.QtWidgets import QLabel
        from PySide6.QtGui import QPixmap

        label = QLabel()
        label.resize(model.width, model.height)
        label.setAlignment(Qt.AlignmentFlag.AlignCenter)

        image_path = getattr(model, 'image_path', '')
        if image_path:
            try:
                pixmap = QPixmap(image_path)
                if not pixmap.isNull():
                    scaled_pixmap = pixmap.scaled(
                        model.width, model.height,
                        Qt.AspectRatioMode.KeepAspectRatio,
                        Qt.TransformationMode.SmoothTransformation
                    )
                    label.setPixmap(scaled_pixmap)
                else:
                    label.setText(getattr(model, 'placeholder_text', '') or "图片")
            except Exception:
                label.setText(getattr(model, 'placeholder_text', '') or "加载失败")
        else:
            label.setText(getattr(model, 'placeholder_text', '') or "图片")

        StyleHelper.apply_style(label, model.style)
        return label

functions.ProjectConverter.python_to_itexe:
def python_to_itexe(code: str) -> Optional[Dict[str, Any]]:
        """将Python脚本转换回项目数据。

        Args:
            code: Python脚本代码

        Returns:
            项目数据字典，如果转换失败返回None
        """
        try:
            match = re.search(r'def get_project_data\(\)\s*->\s*Dict\[str,\s*Any\]:\s*""".*?"""\s*return\s*(\{.*?\n\s*\})', code, re.DOTALL)

            if match:
                dict_str = match.group(1)
                local_vars = {}
                exec(f'result = {dict_str}', {'Dict': Dict, 'Any': Any}, local_vars)
                return local_vars.get('result')

            json_match = re.search(r'\{[\s\S]*"name"[\s\S]*"windows"[\s\S]*"components"[\s\S]*\}', code)
            if json_match:
                json_str = json_match.group(0)
                return json.loads(json_str)

            return None

        except Exception as e:
            print(f"转换失败: {e}")
            return None

