functions.TempFileManager.cleanup_old_temp_files:
def cleanup_old_temp_files(self, max_age_days: int = 7):
        """清理过期的临时文件。

        Args:
            max_age_days: 文件最大保留天数，默认7天

        ## 修复说明 (2026-04-02)
        新增方法，用于定期清理临时目录中的过期文件。
        """
        temp_dir = tempfile.gettempdir()
        current_time = datetime.now().timestamp()
        max_age_seconds = max_age_days * 24 * 3600

        try:
            for filename in os.listdir(temp_dir):
                if filename.startswith('unsaved_project_') and filename.endswith('.itexe'):
                    file_path = os.path.join(temp_dir, filename)
                    try:
                        file_stat = os.stat(file_path)
                        if current_time - file_stat.st_mtime > max_age_seconds:
                            os.remove(file_path)
                    except OSError:
                        pass
        except OSError:
            pass

