def _get_squeeze_level(self, width_ratio: float, height_ratio: float) -> str:
        """获取挤压程度"""
        max_ratio = max(width_ratio, height_ratio)

        if max_ratio > 2.0:
            return "严重挤压"
        elif max_ratio > 1.5:
            return "中度挤压"
        elif max_ratio > 1.2:
            return "轻微挤压"
        else:
            return "正常"

